import java.util.*;
import java.math.BigDecimal;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

sealed interface DomainEvent permits PaymentInitiatedEvent, PaymentProcessingEvent, PaymentFailedEvent {}
record PaymentInitiatedEvent(String paymentId, BigDecimal amount, String merchantId) implements DomainEvent {}
record PaymentProcessingEvent(String paymentId, String bankRef) implements DomainEvent {}
record PaymentFailedEvent(String paymentId, String reason) implements DomainEvent {}

class PaymentAggregate {
    private String paymentId;
    private String status = "NEW";
    private BigDecimal amount;
    private String failureReason;

    public static PaymentAggregate reconstruct(List<DomainEvent> events) {
        PaymentAggregate agg = new PaymentAggregate();
        for (DomainEvent event : events) {
            switch (event) {
                case PaymentInitiatedEvent e -> agg.apply(e);
                case PaymentProcessingEvent e -> agg.apply(e);
                case PaymentFailedEvent e -> agg.apply(e);
            }
        }
        return agg;
    }

    private void apply(PaymentInitiatedEvent e) { paymentId=e.paymentId(); amount=e.amount(); status="INITIATED"; }
    private void apply(PaymentProcessingEvent e) { status="PROCESSING"; }
    private void apply(PaymentFailedEvent e) { status="FAILED"; failureReason=e.reason(); }

    String getStatus() { return status; }
    String getFailureReason() { return failureReason; }
    BigDecimal getAmount() { return amount; }
}

@SpringBootTest
class PaymentAggregateTest {
    @Test void reconstruct_fromEvents(){
        List<DomainEvent> events = List.of(
            new PaymentInitiatedEvent("PAY-001",new BigDecimal("5000"),"MRC-001"),
            new PaymentProcessingEvent("PAY-001","HDFC-B123"),
            new PaymentFailedEvent("PAY-001","bank_timeout")
        );
        PaymentAggregate agg = PaymentAggregate.reconstruct(events);
        assertEquals("FAILED", agg.getStatus());
        assertEquals("bank_timeout", agg.getFailureReason());
        assertEquals(new BigDecimal("5000"), agg.getAmount());
    }
}

import java.util.*;
import java.time.Instant;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
