import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.math.BigDecimal;

record StoredEvent(String aggregateId, long sequence, String eventType, Object payload, Instant occurredAt) {}

@Service
public class InMemoryEventStore {
    private final List<StoredEvent> store = new ArrayList<>();
    private long sequence = 0;

    public synchronized void append(String aggregateId, String eventType, Object payload) {
        // Append-only: never update or delete!
        store.add(new StoredEvent(aggregateId, ++sequence, eventType, payload, Instant.now()));
    }

    public List<StoredEvent> loadEvents(String aggregateId) {
        return store.stream()
            .filter(e -> e.aggregateId().equals(aggregateId))
            .sorted(Comparator.comparingLong(StoredEvent::sequence))
            .toList();
    }

    public int totalEvents() { return store.size(); }
}

@SpringBootTest
class EventStoreTest {
    @Autowired InMemoryEventStore eventStore;

    @Test void appendAndLoad_inOrder(){
        String paymentId = "PAY-ES-" + System.nanoTime();
        eventStore.append(paymentId, "PaymentInitiated", new BigDecimal("5000"));
        eventStore.append(paymentId, "PaymentProcessing", "HDFC-B123");
        eventStore.append(paymentId, "PaymentFailed", "bank_timeout");

        List<StoredEvent> events = eventStore.loadEvents(paymentId);
        assertEquals(3, events.size());
        assertEquals("PaymentInitiated", events.get(0).eventType());
        assertEquals("PaymentProcessing", events.get(1).eventType());
        assertEquals("PaymentFailed", events.get(2).eventType());
    }
}

