class TemporalPaymentAggregate {
    private String status = "NEW";

    public static TemporalPaymentAggregate reconstruct(List<DomainEvent> events) {
        return reconstructUpTo(events, events.size());
    }

    // Temporal query: state at event N
    public static TemporalPaymentAggregate reconstructUpTo(List<DomainEvent> events, int upToN) {
        TemporalPaymentAggregate agg = new TemporalPaymentAggregate();
        events.stream().limit(upToN).forEach(e -> {
            if (e instanceof PaymentInitiatedEvent) agg.status = "INITIATED";
            else if (e instanceof PaymentProcessingEvent) agg.status = "PROCESSING";
            else if (e instanceof PaymentFailedEvent) agg.status = "FAILED";
        });
        return agg;
    }

    String getStatus() { return status; }
}

@SpringBootTest
class TemporalQueryTest {
    List<DomainEvent> paymentEvents = List.of(
        new PaymentInitiatedEvent("P1", new BigDecimal("5000"), "MRC-001"),
        new PaymentProcessingEvent("P1", "B123"),
        new PaymentFailedEvent("P1", "timeout")
    );

    @Test void stateAtEvent1_isInitiated(){
        assertEquals("INITIATED", TemporalPaymentAggregate.reconstructUpTo(paymentEvents, 1).getStatus());
    }
    @Test void stateAtEvent2_isProcessing(){
        assertEquals("PROCESSING", TemporalPaymentAggregate.reconstructUpTo(paymentEvents, 2).getStatus());
    }
    @Test void stateAtEvent3_isFailed(){
        assertEquals("FAILED", TemporalPaymentAggregate.reconstructUpTo(paymentEvents, 3).getStatus());
    }
}

