import java.util.*;
import java.math.BigDecimal;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

record AggregateSnapshot(String aggregateId, long lastSequence, String status) {}

@Service
class SnapshotStore {
    private final Map<String, AggregateSnapshot> snapshots = new HashMap<>();
    void save(AggregateSnapshot s) { snapshots.put(s.aggregateId(), s); }
    Optional<AggregateSnapshot> load(String id) { return Optional.ofNullable(snapshots.get(id)); }
}

@Service
class SnapshotPaymentRepo {
    private final InMemoryEventStore eventStore;
    private final SnapshotStore snapshots;
    SnapshotPaymentRepo(InMemoryEventStore e, SnapshotStore s) { eventStore=e; snapshots=s; }

    public PaymentAggregate load(String paymentId) {
        // Check for snapshot:
        Optional<AggregateSnapshot> snap = snapshots.load(paymentId);
        List<StoredEvent> events;
        if (snap.isPresent()) {
            // Load only events AFTER snapshot:
            events = eventStore.loadEvents(paymentId).stream()
                .filter(e -> e.sequence() > snap.get().lastSequence())
                .toList();
            // Restore state from snapshot:
            PaymentAggregate agg = new PaymentAggregate();
            agg.restoreFromSnapshot(snap.get().status());
            events.forEach(e -> agg.applyStoredEvent(e.eventType()));
            return agg;
        } else {
            // No snapshot: replay all events:
            events = eventStore.loadEvents(paymentId);
            PaymentAggregate agg = new PaymentAggregate();
            events.forEach(e -> agg.applyStoredEvent(e.eventType()));
            return agg;
        }
    }

    public void saveSnapshot(String paymentId, String status, long seq) {
        snapshots.save(new AggregateSnapshot(paymentId, seq, status));
    }
}

// Extend PaymentAggregate for snapshot support:
class PaymentAggregate {
    String status = "NEW";
    void restoreFromSnapshot(String s) { status = s; }
    void applyStoredEvent(String type) {
        status = switch(type) {
            case "PaymentInitiated" -> "INITIATED";
            case "PaymentProcessing" -> "PROCESSING";
            case "PaymentFailed" -> "FAILED";
            default -> status;
        };
    }
    String getStatus() { return status; }
}

@SpringBootTest
class SnapshotTest {
    @Autowired InMemoryEventStore eventStore;
    @Autowired SnapshotStore snapshots;
    @Autowired SnapshotPaymentRepo repo;

    @Test void snapshotReducesReplay() {
        String id = "PAY-SNAP-" + System.nanoTime();
        eventStore.append(id, "PaymentInitiated", null);
        eventStore.append(id, "PaymentProcessing", null);
        // Snapshot at event 2 (PROCESSING state):
        repo.saveSnapshot(id, "PROCESSING", 2);
        eventStore.append(id, "PaymentFailed", null);

        // Load: should use snapshot + only replay event 3
        PaymentAggregate agg = repo.load(id);
        assertEquals("FAILED", agg.getStatus());
    }
}

