import java.util.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// V1 event (old schema):
record PaymentFailedEventV1(String paymentId, String reason, String failureCode) {}

// V2 event (new schema — added 'retryable'):
record PaymentFailedEventV2(String paymentId, String reason, String failureCode, boolean retryable) {}

// Upcaster: converts V1 to V2 (applied when reading old events):
@Service
public class PaymentFailedEventUpcaster {
    public PaymentFailedEventV2 upcast(PaymentFailedEventV1 v1) {
        // Business rule: retryable unless it was FRAUD:
        boolean retryable = !"FRAUD".equals(v1.failureCode());
        return new PaymentFailedEventV2(
            v1.paymentId(), v1.reason(), v1.failureCode(), retryable);
    }

    // Upcaster registry pattern:
    public Object upcast(Object rawEvent, String eventVersion) {
        return switch (eventVersion) {
            case "PaymentFailedEvent_v1" -> upcast((PaymentFailedEventV1) rawEvent);
            case "PaymentFailedEvent_v2" -> rawEvent; // already latest
            default -> rawEvent;
        };
    }

    // WHY UPCASTING (not migration):
    // Events are immutable — can't change stored events!
    // When reading old events: upcast on-the-fly to latest version
    // Downside: must keep upcasters for every schema version
    // Alternative: store events as JSON, deserialize to latest schema (add optional fields)
}

@SpringBootTest
class UpcastTest {
    @Autowired PaymentFailedEventUpcaster upcaster;

    @Test void v1_upcastToV2_notFraud(){
        var v1 = new PaymentFailedEventV1("P1","bank_timeout","TIMEOUT");
        var v2 = upcaster.upcast(v1);
        assertEquals("TIMEOUT",v2.failureCode());
        assertTrue(v2.retryable()); // TIMEOUT is retryable
    }
    @Test void v1_upcastToV2_fraud(){
        var v1 = new PaymentFailedEventV1("P1","fraud detected","FRAUD");
        var v2 = upcaster.upcast(v1);
        assertFalse(v2.retryable()); // FRAUD is NOT retryable
    }
}

import java.util.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.concurrent.atomic.AtomicInteger;

@Service
public class FailureAnalyticsProjection {
    // New projection built by replaying historical events:
    private final Map<String, AtomicInteger> failureCounts = new HashMap<>();

    // Called during replay (processes past events):
    public void replay(List<StoredEvent> events) {
        events.stream()
            .filter(e -> e.eventType().equals("PaymentFailed"))
            .forEach(e -> {
                // Parse failure code from payload (simplified):
                String code = parseFailureCode(e.payload().toString());
                failureCounts.computeIfAbsent(code, k -> new AtomicInteger(0)).incrementAndGet();
            });
    }

    // Called for live events (same logic):
    public void onPaymentFailed(String failureCode) {
        failureCounts.computeIfAbsent(failureCode, k -> new AtomicInteger(0)).incrementAndGet();
    }

    public int getFailureCount(String failureCode) {
        return failureCounts.getOrDefault(failureCode, new AtomicInteger(0)).get();
    }

    private String parseFailureCode(String payload) {
        // Simplified: in real system use ObjectMapper
        if (payload.contains("TIMEOUT")) return "TIMEOUT";
        if (payload.contains("FRAUD")) return "FRAUD";
        if (payload.contains("INSUFFICIENT")) return "INSUFFICIENT_FUNDS";
        return "UNKNOWN";
    }
}

@SpringBootTest
class ReplayProjectionTest {
    @Autowired FailureAnalyticsProjection projection;
    @Autowired InMemoryEventStore store;

    @Test void replay_countsFailuresCorrectly(){
        // Create historical events:
        String p1="PAY-R1", p2="PAY-R2", p3="PAY-R3";
        store.append(p1,"PaymentFailed","TIMEOUT");
        store.append(p2,"PaymentFailed","TIMEOUT");
        store.append(p3,"PaymentFailed","FRAUD");
        store.append("PAY-R4","PaymentInitiated","5000"); // not a failure

        // Replay all historical events:
        List<StoredEvent> allEvents=store.loadEvents(p1);
        allEvents=new ArrayList<>(allEvents);
        allEvents.addAll(store.loadEvents(p2));
        allEvents.addAll(store.loadEvents(p3));
        projection.replay(allEvents);

        assertEquals(2, projection.getFailureCount("TIMEOUT"));
        assertEquals(1, projection.getFailureCount("FRAUD"));
    }
}

