sealed interface PEvent permits PIEvent,PPEvent,PFEvent{}
record PIEvent(String id,BigDecimal amt) implements PEvent{}
record PPEvent(String id,String ref) implements PEvent{}
record PFEvent(String id,String reason) implements PEvent{}

class PAggregate {
    String status="NEW"; BigDecimal amount;
    List<PEvent> changes=new ArrayList<>();
    static PAggregate reconstruct(List<PEvent> events){
        PAggregate a=new PAggregate();
        events.forEach(e->{
            if(e instanceof PIEvent i){a.status="INITIATED";a.amount=i.amt();}
            else if(e instanceof PPEvent){a.status="PROCESSING";}
            else if(e instanceof PFEvent){a.status="FAILED";}
        });
        return a;
    }
    void initiate(BigDecimal amt){
        PIEvent e=new PIEvent("P"+System.nanoTime(),amt);
        apply(e);changes.add(e);
    }
    void fail(String reason){
        PFEvent e=new PFEvent("P1",reason);
        apply(e);changes.add(e);
    }
    void apply(PEvent e){
        if(e instanceof PIEvent i){status="INITIATED";amount=i.amt();}
        else if(e instanceof PPEvent){status="PROCESSING";}
        else if(e instanceof PFEvent){status="FAILED";}
    }
    List<PEvent> getChanges(){return changes;}
    String getStatus(){return status;}
    BigDecimal getAmount(){return amount;}
}

@Service class SimpleEventStore {
    Map<String,List<PEvent>> store=new HashMap<>();
    void append(String id,List<PEvent> events){store.computeIfAbsent(id,k->new ArrayList<>()).addAll(events);}
    List<PEvent> load(String id){return store.getOrDefault(id,List.of());}
}

@Service class PStatusProjection {
    Map<String,String> statusIndex=new HashMap<>();
    void rebuild(String id,List<PEvent> events){
        PAggregate a=PAggregate.reconstruct(events);
        statusIndex.put(id,a.getStatus());
    }
    String getStatus(String id){return statusIndex.get(id);}
}

@SpringBootTest
class ESCompleteTest {
