@Entity @Table(name="rzp_events")
class RzpEventRecord {
    @Id @GeneratedValue Long id;
    String aggregateId,eventType,payload;
    long seq;
    Instant at=Instant.now();
    RzpEventRecord(){}
    RzpEventRecord(String aId,String type,String payload,long seq){aggregateId=aId;eventType=type;this.payload=payload;this.seq=seq;}
    String getEventType(){return eventType;}
    String getPayload(){return payload;}
}
interface RzpEventRepo extends JpaRepository<RzpEventRecord,Long>{
    List<RzpEventRecord> findByAggregateIdOrderBySeqAsc(String id);
    long countByAggregateId(String id);
}

class RzpPaymentAgg {
    String status="NEW"; BigDecimal amount;
    List<String[]> changes=new ArrayList<>();
    static RzpPaymentAgg reconstruct(List<RzpEventRecord> recs){
        RzpPaymentAgg a=new RzpPaymentAgg();
        recs.forEach(r->a.applyType(r.getEventType(),r.getPayload()));
        return a;
    }
    void applyType(String t,String payload){
        status=switch(t){
            case "PaymentInitiated"->"INITIATED";
            case "ProcessingStarted"->"PROCESSING";
            case "BankTimeout"->"TIMEOUT";
            case "PaymentFailed"->"FAILED";
            default->status;
        };
    }
    void initiate(BigDecimal amt){amount=amt;applyType("PaymentInitiated","");changes.add(new String[]{"PaymentInitiated",amt.toString()});}
    void startProcessing(){applyType("ProcessingStarted","");changes.add(new String[]{"ProcessingStarted",""}); }
    void timeout(){applyType("BankTimeout","");changes.add(new String[]{"BankTimeout",""}); }
    void fail(){applyType("PaymentFailed","");changes.add(new String[]{"PaymentFailed",""}); }
    String getStatus(){return status;}
}

@Service class RzpESService {
    private final RzpEventRepo repo;
    RzpESService(RzpEventRepo r){repo=r;}
    void save(String id,RzpPaymentAgg agg){
        long next=repo.countByAggregateId(id)+1;
        for(String[] c:agg.changes) repo.save(new RzpEventRecord(id,c[0],c[1],next++));
    }
    RzpPaymentAgg load(String id){return RzpPaymentAgg.reconstruct(repo.findByAggregateIdOrderBySeqAsc(id));}
}

@DataJpaTest
@Import(RzpESService.class)
class RzpESTest {
    @Autowired RzpESService svc;
    @Autowired RzpEventRepo repo;

    @Test void append_storesEvents(){
        RzpPaymentAgg agg=new RzpPaymentAgg();agg.initiate(new BigDecimal("5000"));
        svc.save("PAY-JPA-1",agg);
        assertEquals(1,repo.findByAggregateIdOrderBySeqAsc("PAY-JPA-1").size());
