import jakarta.persistence.*;
import org.springframework.data.jpa.repository.*;
import org.springframework.stereotype.*;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.context.annotation.Import;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Instant;

@Entity @Table(name="concurrent_events",
    uniqueConstraints=@UniqueConstraint(columnNames={"agg_id","seq"}))
class ConcurrentEvent {
    @Id @GeneratedValue Long id;
    @Column(name="agg_id") String aggId;
    String eventType;
    long seq;
    Instant at=Instant.now();
    ConcurrentEvent(){}
    ConcurrentEvent(String aId,String t,long s){aggId=aId;eventType=t;seq=s;}
}
interface ConcurrentEventRepo extends JpaRepository<ConcurrentEvent,Long>{
    long countByAggId(String id);
}

class ConcurrentModificationException extends RuntimeException {
    ConcurrentModificationException(String m){super(m);}
}

@Service class OptimisticEventStore {
    private final ConcurrentEventRepo repo;
    OptimisticEventStore(ConcurrentEventRepo r){repo=r;}

    void append(String aggId, String eventType, long expectedVersion) {
        long current = repo.countByAggId(aggId);
        if (current != expectedVersion) {
            throw new ConcurrentModificationException(
                "Expected version "+expectedVersion+" but got "+current);
        }
        try {
            repo.saveAndFlush(new ConcurrentEvent(aggId, eventType, current+1));
        } catch (DataIntegrityViolationException e) {
            throw new ConcurrentModificationException("Concurrent write detected for "+aggId);
        }
    }
}

@DataJpaTest
@Import(OptimisticEventStore.class)
class OptimisticLockTest {
    @Autowired OptimisticEventStore store;

    @Test void firstWrite_succeeds(){
        store.append("AGG-OPT-1","EventA",0); // version 0 = no events yet
    }
    @Test void wrongVersion_throws(){
        store.append("AGG-OPT-2","EventA",0);
        // Try to write second event with wrong expected version:
        assertThrows(ConcurrentModificationException.class,
            ()->store.append("AGG-OPT-2","EventB",0)); // should be version 1 now
    }
}

import java.util.*;
import java.math.BigDecimal;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

sealed interface SE2 permits SE2I,SE2P,SE2F{}
record SE2I(String id,BigDecimal amt) implements SE2{}
record SE2P(String id) implements SE2{}
record SE2F(String id,String r) implements SE2{}

class Agg2 {
    String status="NEW";BigDecimal amount;
    List<SE2> changes=new ArrayList<>();
    static Agg2 reconstruct(List<SE2> evs,int limit){
        Agg2 a=new Agg2();
        evs.stream().limit(limit).forEach(e->{
            if(e instanceof SE2I i){a.status="INITIATED";a.amount=i.amt();}
            else if(e instanceof SE2P){a.status="PROCESSING";}
            else if(e instanceof SE2F){a.status="FAILED";}
        });
        return a;
    }
    void initiate(BigDecimal amt){SE2I e=new SE2I("P1",amt);if(status.equals("NEW")){status="INITIATED";amount=amt;changes.add(e);}}
    void fail(String r){SE2F e=new SE2F("P1",r);status="FAILED";changes.add(e);}
    String getStatus(){return status;}
    BigDecimal getAmount(){return amount;}
    List<SE2> getChanges(){return changes;}
}

@Service class Store2 {
    Map<String,List<SE2>> db=new HashMap<>();
    void append(String id,List<SE2> evs){db.computeIfAbsent(id,k->new ArrayList<>()).addAll(evs);}
    List<SE2> load(String id){return db.getOrDefault(id,List.of());}
}

@Service class Proj2 {
    Map<String,String> idx=new HashMap<>();
    void index(String id,List<SE2> evs){
        idx.put(id,Agg2.reconstruct(evs,evs.size()).getStatus());
    }
    String get(String id){return idx.get(id);}
}

@Service class Snap2 {
    Map<String,String[]> snaps=new HashMap<>();
    void save(String id,String status,int seq){snaps.put(id,new String[]{status,String.valueOf(seq)});}
    Optional<String[]> load(String id){return Optional.ofNullable(snaps.get(id));}
}

@SpringBootTest
class M24T2SynthesisTest {
    @Autowired Store2 store;
    @Autowired Proj2 proj;
    @Autowired Snap2 snap;

    @Test void reconstruct_stateCorrect(){
        Agg2 a=new Agg2();a.initiate(new BigDecimal("5000"));a.fail("timeout");
        store.append("P-S1",a.getChanges());
        Agg2 r=Agg2.reconstruct(store.load("P-S1"),Integer.MAX_VALUE);
        assertEquals("FAILED",r.getStatus());
        assertEquals(new BigDecimal("5000"),r.getAmount());
    }
    @Test void temporalQuery_atEvent1(){
        Agg2 a=new Agg2();a.initiate(new BigDecimal("3000"));a.fail("fraud");
        store.append("P-S2",a.getChanges());
        Agg2 at1=Agg2.reconstruct(store.load("P-S2"),1);
        assertEquals("INITIATED",at1.getStatus());
    }
    @Test void projection_buildsIndex(){
        Agg2 a=new Agg2();a.initiate(new BigDecimal("2000"));
        store.append("P-S3",a.getChanges());
        proj.index("P-S3",store.load("P-S3"));
        assertEquals("INITIATED",proj.get("P-S3"));
    }
    @Test void snapshot_reducesReplay(){
        snap.save("P-S4","PROCESSING",2); // snapshot at event 2
        Optional<String[]> s=snap.load("P-S4");
        assertTrue(s.isPresent());
        assertEquals("PROCESSING",s.get()[0]);
        assertEquals("2",s.get()[1]);
    }
}
